import React, { useState, useEffect } from 'react';

// Dummy AddThread component for the form
function AddThread({ onAdd }) {
    const [title, setTitle] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();

        // Call API to add thread - adjust URL and data shape as needed
        const res = await fetch('/api/threads', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title }),
        });

        if (res.ok) {
            const newThread = await res.json();
            onAdd(newThread);  // Add new thread to parent state
            setTitle('');      // Clear input
        } else {
            alert('Failed to add thread');
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <input
                type="text"
                placeholder="Thread title"
                value={title}
                onChange={e => setTitle(e.target.value)}
                required
            />
            <button type="submit">Add Thread</button>
        </form>
    );
}

// Example Threads list component
function ThreadsColumn({ threads }) {
    return (
        <div style={{ maxHeight: 300, overflowY: 'auto' }}>
            {threads.map(thread => (
                <div key={thread.id} style={{ border: '1px solid #ccc', margin: 8, padding: 8, cursor: 'pointer' }}
                     onClick={() => window.location.href = `/thread/${thread.id}`}
                >
                    {thread.title}
                </div>
            ))}
        </div>
    );
}

export default function Dashboard() {
    const [threads, setThreads] = useState([]);

    useEffect(() => {
        // Fetch existing threads on mount
        async function fetchThreads() {
            const res = await fetch('/api/threads');
            if (res.ok) {
                const data = await res.json();
                setThreads(data);
            }
        }
        fetchThreads();
    }, []);

    const handleAddThread = (newThread) => {
        setThreads(prev => [newThread, ...prev]);
    };

    return (
        <div>
            <h2>Threads</h2>
            <AddThread onAdd={handleAddThread} />
            <ThreadsColumn threads={threads} />
        </div>
    );
}
